interface Props {
  src?: string
  alt: string
  width?: number
  height?: number
  fill?: boolean
  className?: string
  containerClassName?: string
  priority?: boolean
}

export function SafeImage({ src, alt, width = 400, height = 300, fill, className = "", containerClassName = "", priority = false }: Props) {
  const [loaded, setLoaded] = useState(false)
  const [error, setError] = useState(false)

  if (!src || error) {
    return (
      <div className={"flex items-center justify-center bg-muted " + containerClassName}>
        <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="[REDACTED_PHONE]" fill="none" stroke="currentColor" strokeWidth="1" className="text-muted-foreground/40">
